INSERT INTO essays (slug, title, subtitle, category, read_time, content, is_published, published_at) VALUES ('ai-doesn-t-replace-engineers-it-removes-the-knowledge-ceiling', 'AI doesn''t replace engineers - it removes the knowledge ceiling', 'Two years of embedding AI tools across engineering teams. What actually changed.', 'Technical', '8 min', '<p class="lede">For two years I''ve been embedding AI tools across engineering teams - not just personally, but at scale. Custom prompts. Agent-driven CI. LLM-powered code review. The results aren''t what most people predicted.</p>\n<p>The lazy take is that AI replaces engineers. The honest answer, after thousands of merged PRs across @sociable-tech and @pitb-iep, is that AI removes the knowledge ceiling. There was always a gap between knowing what to build and being able to build it precisely. That gap is collapsing.</p>\n<h2>What changed, concretely</h2>\n<p>A junior engineer on my team shipped a Postgres migration with row-level security on her third week. Five years ago that would have been a senior task. Not because she suddenly knew RLS - because the tool let her ask the right questions in the right order, and her judgment about whether the answer made sense was the actual skill.</p>\n<p>Across a 7-person team, we shipped what a 16-person team shipped in 2022. Same domain, same compliance, same client expectations. The geometry of work changed; the discipline did not.</p>\n<blockquote>"AI doesn''t replace the engineer. It removes the knowledge ceiling - and that makes craftsmanship more important, not less."</blockquote>\n<h2>What didn''t change</h2>\n<p>Taste. Architecture. The ability to say no. The willingness to refactor instead of bolting on. None of these get easier when generation is cheap. If anything, the cost of bad calls compounds faster because you can ship them faster.</p>\n<p>Good code is still an art form. AI just gives every artist a better brush.</p>', true, '2026-04-22T00:00:00.000Z');
INSERT INTO essays (slug, title, subtitle, category, read_time, content, is_published, published_at) VALUES ('how-i-architected-chasyr-s-voice-agents-to-stay-accc-compliant', 'How I architected Chasyr''s voice agents to stay ACCC-compliant', 'Compliance as a first-class constraint, not an afterthought. State-machine + audit log + human escalation.', 'Technical', '12 min', '<p class="lede">Building a voice agent that calls Australian small businesses about overdue invoices means living inside ACCC compliance. Here''s how I architected for it from day one.</p>\n<p>Most voice-agent stacks treat compliance as a wrapper - a profanity filter, a recording-disclosure prompt, a kill switch. That''s wrong. Compliance is a first-class architectural constraint, the same way idempotency is for payments.</p>\n<h2>The state machine</h2>\n<p>Every Chasyr call is a finite state machine with auditable transitions. Greeting → identity verification → reason → negotiation → outcome → disclosure → close. The LLM picks the words; the state machine picks what state we can move to. The model never gets to invent a new state. That single constraint kills 80% of compliance risk.</p>\n<h2>Human escalation as a feature, not a fallback</h2>\n<p>If the caller asks anything outside the trained surface - a complaint, a dispute, a hardship claim - we transfer. Cheerfully, immediately, no negotiation. Engineers wanted to handle more in-agent. The product called it correctly: the cost of one bad call is greater than the cost of a hundred warm transfers.</p>\n<blockquote>"The model picks the words. The state machine picks what state we can move to."</blockquote>\n<p>There''s more - audit log structure, retention windows, consent capture mechanics. I''ll cover them in part two.</p>', true, '2026-04-08T00:00:00.000Z');
INSERT INTO essays (slug, title, subtitle, category, read_time, content, is_published, published_at) VALUES ('on-building-from-lahore-for-the-world', 'On building from Lahore for the world', 'What I''ve learned shipping international SaaS products from Pakistan: trust, timezones, and the long game.', 'Personal', '6 min', '<p class="lede">I''ve shipped international SaaS from Lahore for a decade. The lessons are not what people on Twitter say they are.</p>\n<p>The first myth is timezone. People assume Pakistan-to-Australia is the easy match. It is. But timezone is a tax on attention, not on output. The output question is trust.</p>\n<h2>Trust is the long compounding bet</h2>\n<p>Every contract I have today is downstream of work I did two years ago for a client who is no longer with me. The Pakistani engineer''s problem isn''t skill - it''s the cold-start penalty on trust. You can either pay that off in years, or you can buy your way out with a referral network. There is no third option.</p>\n<h2>What I''d tell my younger self</h2>\n<p>Pick fewer clients. Charge more. Write publicly. Be unfashionably honest about deadlines. The market for credibility from a city like Lahore is thin enough that any signal travels far.</p>', true, '2026-03-30T00:00:00.000Z');
INSERT INTO essays (slug, title, subtitle, category, read_time, content, is_published, published_at) VALUES ('sabr-in-software-patience-as-engineering-discipline', 'Sabr in software - patience as engineering discipline', 'The Islamic concept of sabr, and what it taught me about debugging, hiring, and the long compounding of small bets.', 'Religious', '5 min', '<p class="lede">In Islam, sabr is often translated as "patience" - but it''s closer to "discipline through difficulty." It maps onto software work better than any productivity book I''ve read.</p>\n<p>A bug that resists three days of debugging is a sabr exercise. A hire that doesn''t pan out, a launch that lands soft, a quarter that misses - sabr. Not stoic numbness. Active, deliberate patience.</p>\n<blockquote>"Sabr is not the absence of struggle. It is the discipline to stay in it without being deformed by it."</blockquote>\n<h2>The compounding of small bets</h2>\n<p>Every venture I''ve started has needed two years to feel like anything. Chasyr is in early access at 200+ on the waitlist; that line on the chart is the visible part of work that was invisible for 18 months. Sabr is what protects you from the temptation to pivot off something that just hasn''t finished baking.</p>\n<p>The Quran pairs sabr with shukr - gratitude. They aren''t opposites. Patience without gratitude is grinding. Gratitude without patience is naive. The combination is the closest thing I''ve found to a working engineering temperament.</p>', true, '2026-03-12T00:00:00.000Z');
INSERT INTO essays (slug, title, subtitle, category, read_time, content, is_published, published_at) VALUES ('rag-pipelines-i-d-never-ship-to-prod-and-the-ones-i-would', 'RAG pipelines I''d never ship to prod (and the ones I would)', 'Three years of vector DB war stories. Chunking strategies, embedding drift, and the lie of cosine similarity.', 'Technical', '14 min', '<p class="lede">Three years of vector DB war stories. What I''d ship today, and what I''d burn down on sight.</p>\n<p>Cosine similarity is a lie agreed upon. It works, mostly, until your corpus drifts - and then it fails silently, with confidence. That alone disqualifies it from any system where a wrong answer has a cost.</p>\n<h2>Chunking is policy, not optimisation</h2>\n<p>Decide what a chunk MEANS to your retrieval target. A legal clause? A code function? A line of dialogue? Pick the semantic unit first, the byte size second. Every team I''ve seen get RAG wrong picked byte size first.</p>\n<h2>When I''d still ship RAG</h2>\n<p>Domains where the corpus updates daily and the cost of a wrong answer is bounded. Customer support, internal docs, recommendation. Domains where the corpus is sacred - medical, legal, financial - demand a different architecture. I''ll write that up next.</p>', true, '2026-02-20T00:00:00.000Z');
INSERT INTO essays (slug, title, subtitle, category, read_time, content, is_published, published_at) VALUES ('on-the-discipline-of-five-daily-prayers-as-an-engineer', 'On the discipline of five daily prayers, as an engineer', 'Five context switches a day, on purpose. Notes on rhythm, intent, and what no IDE can give you.', 'Religious', '4 min', '<p class="lede">Five context switches a day, on purpose. Notes from an engineer praying through deadlines.</p>\n<p>I pray five times a day. I don''t do it because it makes me a better engineer - I do it because I''m a Muslim. But living inside that rhythm has taught me things about focus that no productivity stack ever did.</p>\n<blockquote>"Five forced disengagements. Five chances to re-anchor. The work after is never the same as the work before."</blockquote>\n<p>The IDE will not give you a stop signal. The market will not. Your team will not. You need an external clock, and prayer is the most reliable one I''ve found.</p>', true, '2026-02-05T00:00:00.000Z');
INSERT INTO essays (slug, title, subtitle, category, read_time, content, is_published, published_at) VALUES ('a-7-person-team-can-outship-a-70-person-team-here-s-the-geometry', 'A 7-person team can outship a 70-person team - here''s the geometry', 'How I structure AI-first engineering pods. Custom prompts, agent-driven CI, and the math of removed handoffs.', 'Technical', '10 min', '<p class="lede">A 7-person AI-first team can outship a 70-person team. The geometry isn''t magic - it''s removed handoffs.</p>\n<p>Every traditional engineering org pays a hidden tax: the cost of moving work between specialists. PM writes spec. Designer mocks. Frontend takes mock. Backend takes spec. QA tests both. PM closes. That''s six handoffs for one feature. Each handoff loses context and adds latency.</p>\n<h2>What AI removes</h2>\n<p>When a single engineer can specify, design, build, and test - with AI doing the parts they''re weak on - the handoff count drops to zero. The bottleneck moves to taste and decision-making, which is exactly where you want it.</p>\n<h2>What it doesn''t</h2>\n<p>You still need a clear product line. A flat seven-person team without a strong PM voice will ship seven things in seven directions. The role doesn''t go away; it gets concentrated.</p>', true, '2026-01-18T00:00:00.000Z');
INSERT INTO essays (slug, title, subtitle, category, read_time, content, is_published, published_at) VALUES ('i-almost-quit-engineering-in-2019-here-s-what-brought-me-back', 'I almost quit engineering in 2019. Here''s what brought me back.', 'A year of feeling stuck. A government contract that wasn''t supposed to matter. And a quiet rebuild.', 'Personal', '7 min', '<p class="lede">In 2019 I almost left engineering. I want to write about what brought me back, because someone reading this might be in the same place.</p>\n<p>I was at a TV streaming company, fixing bugs nobody noticed, on a stack nobody loved. I had stopped reading code outside work. I had stopped writing. I had a daughter and a mortgage and a feeling that the next ten years would be a copy of the previous one.</p>\n<h2>The unlikely turn</h2>\n<p>A government contract - the kind everyone tells you to avoid - dropped onto my desk in late 2018. CMS work for the Punjab Information Technology Board. Boring on paper. But the constraints were so brutal, and the users so real, that I started caring again. Five thousand digital resources. Forty percent more access to educational content. People I''d never meet, learning from something I helped ship.</p>\n<blockquote>"What brought me back wasn''t a better stack. It was a colder reminder of who the work was for."</blockquote>\n<p>I''m writing this seven years later, having shipped at scale, having built ventures, having advised governments. The thread back to that contract is unbroken. If you''re in a place that feels stuck, the move is not to chase a shinier stack. It''s to find a user.</p>', true, '2025-12-22T00:00:00.000Z');
INSERT INTO education (slug, type, title, description, meta_tags, sort_order) VALUES ('building-production-voice-agents-that-don-t-embarrass-you', 'tutorial', 'Building production voice agents that don''t embarrass you', '<p class="lede">A voice agent that handles negotiations with real humans is not the same as a chatbot. Here''s the architecture that keeps Chasyr production-ready.</p><h2>The state machine</h2><p>Every call follows a finite state machine. Greeting → identity check → reason disclosure → negotiation → outcome → compliance close. The LLM generates natural language; the state machine gates which states are reachable. This single constraint eliminates 80% of failure modes.</p><h2>Audio pipeline</h2><p>Real-time audio requires careful buffering. We use Deepgram for transcription, pipe to Claude for reasoning, and use Elevenlabs for voice synthesis. Latency matters more than fidelity.</p><h2>Fallback design</h2><p>When the LLM gets confused, we escalate. No recovery attempts, no retry loops. A warm transfer to a human is cheaper than a bad negotiation.</p>', '["Series · 4 parts","Updated Apr 2026"]'::jsonb, 0);
INSERT INTO education (slug, type, title, description, meta_tags, sort_order) VALUES ('a-pragmatist-s-guide-to-rag-with-code', 'tutorial', 'A pragmatist''s guide to RAG (with code)', '<p class="lede">RAG is not a silver bullet. Here''s when it works, when it doesn''t, and how to know which problem you''re actually solving.</p><p>The hype around RAG is that it lets you ground LLMs in fresh data. In practice, RAG is a retrieval problem disguised as an AI problem. Most failures are at the retrieval stage, not the generation stage.</p><h2>When RAG wins</h2><p>You have a corpus of documents and need the LLM to cite them accurately. RAG shines here. The retrieval step finds relevant context; the LLM synthesizes. You get citations for free.</p><h2>When fine-tuning wins</h2><p>You need the model to learn a new way of reasoning or style of output. Fine-tuning is the right tool. RAG won''t teach the model anything; it only provides context.</p><p>The hard part is knowing which bucket your problem fits into. Hint: if you''re uncertain, start with RAG. It''s easier to debug.</p>', '["Tutorial","Updated Mar 2026"]'::jsonb, 1);
INSERT INTO education (slug, type, title, description, meta_tags, sort_order) VALUES ('ai-first-pr-review-codified', 'tutorial', 'AI-first PR review, codified', '<p class="lede">Every PR on my team gets reviewed by Claude before a human sees it. Here''s the exact prompt and CI setup.</p><p>AI code review isn''t about finding bugs—static analysis does that better. It''s about pedagogical review: explaining trade-offs, questioning assumptions, and raising standards without slowing the team down.</p><h2>The prompt structure</h2><p>We give Claude the full PR diff plus the codebase context. We ask it to review for readability, maintainability, and whether the change leaves the codebase in a better state. We ignore style—linters handle that.</p><h2>CI integration</h2><p>The review runs as a GitHub check. It doesn''t block merges; it educates. Engineers read the comment, decide if it''s valid, and move forward. After a month, code quality visibly improves.</p>', '["Tutorial · Open source","github.com/isheraz/ai-pr"]'::jsonb, 2);
INSERT INTO education (slug, type, title, description, meta_tags, sort_order) VALUES ('next-js-supabase-stripe-a-deployable-starter', 'tutorial', 'Next.js × Supabase × Stripe - a deployable starter', '<p class="lede">Every SaaS I build starts from this template. Auth, billing, database, and AI hooks pre-wired. Here''s what''s included and why.</p><h2>Authentication</h2><p>Supabase Auth with NextAuth.js. Social providers (GitHub, Google) out of the box. Magic links for emails that don''t support social.</p><h2>Database & RLS</h2><p>PostgreSQL with row-level security. Every query is scoped to the authenticated user. Database enforces security, not application code.</p><h2>Billing</h2><p>Stripe integration with webhook handlers for subscription events. Usage-based billing setup is ready to go.</p><p>Clone, replace the secrets, and deploy. You''ll have a production-ready SaaS in an afternoon.</p>', '["Starter kit","github.com/isheraz/saas-kit"]'::jsonb, 3);
INSERT INTO education (slug, type, title, description, meta_tags, sort_order) VALUES ('ai-first-engineering-teams-lahore-devs-meetup', 'talk', 'AI-First Engineering Teams - Lahore Devs Meetup', '<p class="lede">A 7-person team shipping what a 16-person team shipped in 2022. Here''s how.</p><h2>Multiplication, not replacement</h2><p>AI doesn''t replace engineers. It multiplies them. Juniors become mediors in months. Mediors become seniors in weeks. The leverage is asymmetric.</p><h2>What actually changed</h2><p>We stopped hiring for knowledge and started hiring for judgment. We stopped writing boilerplate and started writing architecture. Our velocity numbers went 3x; our hiring numbers stayed flat.</p><h2>The cultural shift</h2><p>This talk walks through the exact changes we made to processes, onboarding, code review, and team structure.</p>', '["Talk · 32 min","November 2025"]'::jsonb, 4);
INSERT INTO education (slug, type, title, description, meta_tags, sort_order) VALUES ('from-pre-sales-to-production-solutions-architect-decoded', 'talk', 'From Pre-sales to Production: Solutions Architect, decoded', '<p class="lede">How to move from pre-sales engineering into an architecture role without taking a step backward.</p><p>Pre-sales teaches you to understand customers, translate business problems into technical ones, and communicate across disciplines. Those skills are foundational for architecture.</p><h2>What transfers, what doesn''t</h2><p>Customer empathy transfers. Speed of understanding transfers. Imposter syndrome also transfers—but it''s unfounded. You know how to learn quickly. Architecture is just learning on a larger scale.</p><h2>The career narrative</h2><p>We walked through three engineer stories: one who moved too fast and burned out, one who moved too slow and got left behind, and one who got the pace right.</p>', '["Lecture","COMSATS · Sep 2025"]'::jsonb, 5);
INSERT INTO education (slug, type, title, description, meta_tags, sort_order) VALUES ('voice-agents-in-regulated-markets', 'talk', 'Voice Agents in Regulated Markets', '<p class="lede">Building AI agents that call humans requires more than good prompts. Here''s the legal, technical, and ethical scaffolding.</p><h2>Compliance from day one</h2><p>Regulations like ACCC in Australia, FTC rules in the US, and GDPR in Europe all apply. They weren''t written for AI agents, which makes them ambiguous. But the spirit is clear: disclose, get consent, provide an out.</p><h2>Technical scaffolding</h2><p>State machines again. Recording and retention windows. Human escalation as a feature. All of this is in the code, not in the prompts.</p><h2>Ethical design</h2><p>The agent should never deceive. The customer should know they''re talking to an AI. Manipulation is technically possible but ethically indefensible.</p>', '["Panel","AusFinTech · 2026"]'::jsonb, 6);
INSERT INTO education (slug, type, title, description, meta_tags, sort_order) VALUES ('books-that-changed-how-i-architect-systems', 'resource', 'Books that changed how I architect systems', '<p class="lede">A short, opinionated list of books that shaped how I think about systems.</p><p>Most architecture books are verbose and outdated. Here are the ones that are neither.</p><h2>The list</h2><ul><li>Domain-Driven Design — Eric Evans. Learn to think in systems.</li><li>Designing Data-Intensive Applications — Martin Kleppmann. Read the chapters on consistency and consensus.</li><li>The Art of Unix Programming — Eric Raymond. Old but timeless.</li><li>Building Microservices — Sam Newman. The chapter on testing is worth the book alone.</li></ul><p>These are the ones I recommend to engineers I mentor. Read them in order.</p>', '["Curated list","12 books"]'::jsonb, 7);
INSERT INTO education (slug, type, title, description, meta_tags, sort_order) VALUES ('tools-i-actually-use-daily', 'resource', 'Tools I actually use, daily', '<p class="lede">My exact dev stack. Updated quarterly.</p><h2>Editor</h2><p>VS Code with Copilot. The debugger integration alone is worth it.</p><h2>Terminal</h2><p>Fish shell. Better history, better completion, better syntax highlighting than Bash.</p><h2>Productivity</h2><p>Linear for task tracking. Slack for async communication. Figma for design. Arc browser for tab management.</p><h2>The rest</h2><p>PostgreSQL. Redis for caching. Stripe for payments. Supabase for the database backend. AWS for compute.</p>', '["Stack","Updated Q2 2026"]'::jsonb, 8);
INSERT INTO education (slug, type, title, description, meta_tags, sort_order) VALUES ('ai-engineering-reading-list', 'resource', 'AI-engineering reading list', '<p class="lede">Papers, blog posts, and talks every AI-focused engineer should read.</p><h2>Foundation</h2><p>Start with Attention Is All You Need if you want the theory. Skip it if you don''t. Either way, read Kaplan et al. on scaling laws.</p><h2>Practice</h2><p>The LLM Prompt Engineering guide from OpenAI. Anthropic''s prompt best practices. Papers on RAG, fine-tuning, and in-context learning.</p><h2>Edge cases</h2><p>Read about jailbreaks not to use them, but to understand the threat model. Read about hallucinations. Read about safety.</p><p>Then build something. Reading without building is theater.</p>', '["Reading list","40+ links"]'::jsonb, 9);
INSERT INTO education (slug, type, title, description, meta_tags, sort_order) VALUES ('resources-for-engineers-from-pakistan', 'resource', 'Resources for engineers from Pakistan', '<p class="lede">Remote work, visa sponsorship, OSS opportunities, and the things I wish someone had told me ten years ago.</p><h2>Getting remote work</h2><p>Companies: Toptal, Gun.io, Arc.dev. You''re competing globally, so your GitHub matters more than your resume.</p><h2>Visa sponsorship</h2><p>Canada, UK, and Germany are engineer-friendly for visa sponsorship. Australia is harder. US requires an employer who wants to fight immigration.</p><h2>OSS scholarships</h2><p>GitHub Sponsors. Patreon. These are real income for maintainers in Pakistan. Build something useful.</p><h2>The long game</h2><p>Build in public. Write. Share your work. The Pakistan engineer tax on trust is real, but it compounds in reverse. Reputation is capital.</p>', '["Career guide","Free"]'::jsonb, 10);
INSERT INTO consulting_tiers (name, price_label, unit, description, features, cta_text, is_featured, badge_text, sort_order) VALUES ('Architecture Audit', '$1,500', '/ engagement', 'A focused diagnostic of your stack, infra, and AI readiness. Written report, no fluff.', '["2-week engagement, async + 2 calls","Full architecture & infra review","AI integration opportunity map","Prioritised, costed roadmap"]'::jsonb, 'Book audit', false, NULL, 0);
