INSERT INTO consulting_tiers (name, price_label, unit, description, features, cta_text, is_featured, badge_text, sort_order) VALUES ('Strategy Call', '$150', '/ 60 min', 'One call. Bring your hardest architecture or AI-adoption question. Leave with a plan.', '["60-min video call","Pre-read of your context","Recorded with action items","One week of follow-up email"]'::jsonb, 'Book a call', false, NULL, 2);
